import PluginType from"./PluginType.js";const mapRendererPlugins=[];function getMapRendererPlugins(){return mapRendererPlugins}const layerRendererPlugins=[];function getLayerRendererPlugins(){return layerRendererPlugins}function register(e,r){let n;switch(e){case PluginType.MAP_RENDERER:(n=mapRendererPlugins).push(r);break;case PluginType.LAYER_RENDERER:(n=layerRendererPlugins).push(r);break;default:throw new Error("Unsupported plugin type: "+e)}}function registerMultiple(n,t){for(let e=0,r=t.length;e<r;++e)register(n,t[e])}export{getMapRendererPlugins,getLayerRendererPlugins,register,registerMultiple};